// src/pages/LastMilePage.jsx
import React, { useEffect, useState } from 'react';
import {
  getLastMileBusStop, getLastMileSuggestion, getAllLastMileOptions,
  haversine, distanceText, walkTime, getBestExit, getBearing, bearingToCompass,
} from '../utils/helpers';

const G      = '#6BAF45';
const G_DARK = '#4a8a2a';
const G_BG   = 'rgba(107,175,69,.1)';
const G_BOR  = 'rgba(107,175,69,.28)';

// ── Fare estimate helper ───────────────────────────────────
function estimateFare(mode, distMeters) {
  const km = distMeters / 1000;
  if (!distMeters || distMeters < 50) {
    const defaults = { walk:'Free', auto:'₹30–₹60', bus:'₹5–₹15', cab:'₹80–₹150', bike:'₹25–₹50' };
    return defaults[mode] || '—';
  }
  switch (mode) {
    case 'walk':  return 'Free';
    case 'auto': {
      const base = Math.max(30, Math.round(km * 15));
      return `₹${base}–₹${Math.round(base * 1.5)}`;
    }
    case 'bus':   return km < 5 ? '₹5–₹10' : '₹10–₹20';
    case 'cab': {
      const base = Math.max(80, Math.round(km * 18 + 40));
      return `₹${base}–₹${Math.round(base * 1.35)}`;
    }
    case 'bike': {
      const base = Math.max(25, Math.round(km * 10 + 15));
      return `₹${base}–₹${Math.round(base * 1.4)}`;
    }
    default: return '—';
  }
}

/* ── SVG Transport icons ────────────────────────────────── */
function AutoIcon({ size = 26 }) {
  const c = G_DARK;
  return (
    <svg width={size} height={Math.round(size * 0.85)} viewBox="0 0 44 37" fill="none">
      <path d="M8 18 Q8 6 22 6 Q34 6 36 18" fill={c} opacity=".12" stroke={c} strokeWidth="1.8" strokeLinecap="round"/>
      <line x1="8" y1="18" x2="8" y2="28" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      <rect x="6" y="16" width="32" height="13" rx="4" fill={c} opacity=".9"/>
      <rect x="24" y="17.5" width="10" height="8" rx="2" fill="white" opacity=".75"/>
      <rect x="7" y="17.5" width="9" height="8" rx="1.5" fill="white" opacity=".3"/>
      <rect x="10" y="5" width="22" height="3" rx="1.5" fill={c} opacity=".5"/>
      <rect x="20" y="19" width="5" height="4" rx="1" fill={c} opacity=".4"/>
      <circle cx="12" cy="31" r="5" stroke={c} strokeWidth="2" fill="white"/>
      <circle cx="12" cy="31" r="2" fill={c} opacity=".7"/>
      <circle cx="30" cy="31" r="5" stroke={c} strokeWidth="2" fill="white"/>
      <circle cx="30" cy="31" r="2" fill={c} opacity=".7"/>
    </svg>
  );
}

function TaxiIcon({ size = 26 }) {
  const c = '#b45309';
  return (
    <svg width={size} height={Math.round(size * 0.75)} viewBox="0 0 44 33" fill="none">
      <rect x="2" y="14" width="40" height="14" rx="4" fill={c} opacity=".9"/>
      <path d="M9 14 L12 7 L32 7 L35 14 Z" fill={c} opacity=".75"/>
      <rect x="12" y="8" width="9" height="6" rx="1.5" fill="white" opacity=".8"/>
      <rect x="23" y="8" width="9" height="6" rx="1.5" fill="white" opacity=".8"/>
      <rect x="16" y="2" width="12" height="5" rx="2" fill="#fbbf24"/>
      <line x1="22" y1="14" x2="22" y2="27" stroke="white" strokeWidth=".8" opacity=".35"/>
      <circle cx="10" cy="29" r="4" stroke={c} strokeWidth="2" fill="white"/>
      <circle cx="10" cy="29" r="1.8" fill={c} opacity=".7"/>
      <circle cx="34" cy="29" r="4" stroke={c} strokeWidth="2" fill="white"/>
      <circle cx="34" cy="29" r="1.8" fill={c} opacity=".7"/>
      <rect x="39" y="18" width="3.5" height="6" rx="1.5" fill="#fef3c7"/>
    </svg>
  );
}

function WalkIcon({ size = 26 }) {
  const c = '#374151';
  return (
    <svg width={Math.round(size * 0.65)} height={size} viewBox="0 0 24 36" fill="none">
      <circle cx="12" cy="4" r="3.5" fill={c} opacity=".85"/>
      <path d="M12 7.5 L10 16 L7 22" stroke={c} strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
      <path d="M12 7.5 L14 16 L17 22" stroke={c} strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
      <path d="M10 10 L6 14" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      <path d="M14 10 L18 13" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      <path d="M10 16 L8 24 L5 30" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
      <path d="M14 16 L16 24 L19 30" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
    </svg>
  );
}

function BikeIcon({ size = 26 }) {
  const c = '#c2410c';
  return (
    <svg width={Math.round(size * 1.15)} height={size} viewBox="0 0 42 36" fill="none">
      <circle cx="30" cy="4" r="3.5" fill={c} opacity=".8"/>
      <path d="M29 7.5 L26 16" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      <path d="M28 10 L33 13" stroke={c} strokeWidth="1.8" strokeLinecap="round"/>
      <path d="M26 16 L14 18 L8 28" stroke={c} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
      <path d="M26 16 L34 18 L34 28" stroke={c} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
      <path d="M14 18 L34 18" stroke={c} strokeWidth="1.5" strokeLinecap="round" opacity=".5"/>
      <path d="M33 12 L36 12" stroke={c} strokeWidth="2.2" strokeLinecap="round"/>
      <path d="M36 10 L36 15" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      <path d="M23 15 L29 15" stroke={c} strokeWidth="2.5" strokeLinecap="round"/>
      <circle cx="8"  cy="28" r="7" stroke={c} strokeWidth="2" fill="none"/>
      <circle cx="8"  cy="28" r="2.5" fill={c} opacity=".5"/>
      <circle cx="34" cy="28" r="7" stroke={c} strokeWidth="2" fill="none"/>
      <circle cx="34" cy="28" r="2.5" fill={c} opacity=".5"/>
    </svg>
  );
}

function BusIconSVG({ size = 26 }) {
  const c = '#1d4ed8';
  return (
    <svg width={Math.round(size * 1.1)} height={size} viewBox="0 0 44 36" fill="none">
      <rect x="2" y="4" width="40" height="26" rx="5" fill={c} opacity=".9"/>
      <rect x="2" y="4" width="40" height="7" rx="5" fill={c}/>
      {[4,12,21,30].map(x => <rect key={x} x={x} y="7" width="7" height="10" rx="2" fill="white" opacity=".75"/>)}
      <rect x="17" y="19" width="10" height="11" rx="1.5" fill="white" opacity=".3"/>
      <rect x="2" y="28" width="40" height="4" rx="2" fill={c} opacity=".6"/>
      <circle cx="10" cy="33" r="3" fill={c}/><circle cx="10" cy="33" r="1.3" fill="white" opacity=".8"/>
      <circle cx="34" cy="33" r="3" fill={c}/><circle cx="34" cy="33" r="1.3" fill="white" opacity=".8"/>
    </svg>
  );
}

const TRANSPORT_META = {
  walk: { label:'Walk',          color:'#374151', bg:'rgba(55,65,81,.06)',  border:'rgba(55,65,81,.14)', icon: s => <WalkIcon size={s}/> },
  auto: { label:'Auto-Rickshaw', color: G_DARK,   bg: G_BG,                border: G_BOR,              icon: s => <AutoIcon size={s}/> },
  bus:  { label:'Bus',           color:'#1d4ed8',  bg:'rgba(29,78,216,.06)',border:'rgba(29,78,216,.2)',  icon: s => <BusIconSVG size={s}/> },
  cab:  { label:'Cab / Taxi',    color:'#b45309',  bg:'rgba(180,83,9,.06)', border:'rgba(180,83,9,.18)', icon: s => <TaxiIcon size={s}/> },
  bike: { label:'Bike Taxi',     color:'#c2410c',  bg:'rgba(194,65,12,.06)',border:'rgba(194,65,12,.18)',icon: s => <BikeIcon size={s}/> },
};

const RIDE_LINKS = {
  uber:  { label:'Uber',  bg:'#111',    fg:'#fff', url:'https://uber.com/app'  },
  ola:   { label:'Ola',   bg:'#16a34a', fg:'#fff', url:'https://olacabs.com'   },
  rapido:{ label:'Rapido',bg:'#ea580c', fg:'#fff', url:'https://rapido.bike'   },
};

function RideBtn({ p }) {
  const c = RIDE_LINKS[p];
  return (
    <a href={c.url} target="_blank" rel="noreferrer" style={{
      padding:'3px 9px', borderRadius:7, fontSize:'.6rem', fontWeight:700,
      background:c.bg, color:c.fg, textDecoration:'none',
      display:'inline-block', letterSpacing:'.3px',
      transition:'opacity .18s',
    }}
      onMouseEnter={e=>e.currentTarget.style.opacity='.8'}
      onMouseLeave={e=>e.currentTarget.style.opacity='1'}
    >{c.label}↗</a>
  );
}

/* ── Compact Glass Transport Card ───────────────────────── */
function GlassCard({ mode, detail, fare, recommended, isSelected, onSelect, distMeters }) {
  const meta = TRANSPORT_META[mode] || TRANSPORT_META.auto;
  const actualFare = fare || estimateFare(mode, distMeters);
  const rides = mode==='cab'?['uber','ola']:mode==='auto'?['ola','rapido']:mode==='bike'?['rapido']:[];

  return (
    <div
      onClick={() => onSelect(mode)}
      style={{
        background: isSelected ? '#fff' : '#fff',
        border: `1.5px solid ${isSelected ? meta.color : 'rgba(0,0,0,.07)'}`,
        borderRadius: 14, padding: '11px 14px',
        cursor: 'pointer', marginBottom: 8,
        boxShadow: isSelected
          ? `0 6px 20px ${meta.border}, 0 2px 8px rgba(0,0,0,.06)`
          : '0 2px 8px rgba(0,0,0,.05)',
        transition: 'all .22s cubic-bezier(.4,0,.2,1)',
        position: 'relative', overflow: 'hidden',
      }}
      onMouseEnter={e => {
        if (!isSelected) {
          e.currentTarget.style.transform='translateY(-2px)';
          e.currentTarget.style.boxShadow=`0 6px 20px rgba(0,0,0,.08)`;
          e.currentTarget.style.borderColor='rgba(107,175,69,.3)';
        }
      }}
      onMouseLeave={e => {
        if (!isSelected) {
          e.currentTarget.style.transform='none';
          e.currentTarget.style.boxShadow='0 2px 8px rgba(0,0,0,.05)';
          e.currentTarget.style.borderColor='rgba(0,0,0,.07)';
        }
      }}
    >
      {isSelected && <div style={{ position:'absolute', top:0, left:0, right:0, height:2.5, background:`linear-gradient(90deg,${meta.color},transparent)`, borderRadius:'14px 14px 0 0' }} />}
      {recommended && !isSelected && (
        <div style={{
          position:'absolute', top:8, right:10, background: meta.color, color:'#fff',
          fontSize:'.52rem', fontWeight:700, padding:'1px 7px', borderRadius:8, letterSpacing:'.4px',
        }}>BEST</div>
      )}

      <div style={{ display:'flex', alignItems:'center', gap:10 }}>
        {/* Icon disc — compact */}
        <div style={{
          width:42, height:42, borderRadius:11, flexShrink:0,
          background: isSelected ? meta.bg : 'rgba(240,240,238,.9)',
          border:`1px solid ${isSelected ? meta.border : 'rgba(0,0,0,.07)'}`,
          display:'flex', alignItems:'center', justifyContent:'center',
          transition:'all .22s',
        }}>
          {meta.icon(22)}
        </div>

        {/* Text block */}
        <div style={{ flex:1, minWidth:0 }}>
          <div style={{ fontWeight:700, fontSize:'.84rem', color:'#1a1a18', marginBottom:1 }}>{meta.label}</div>
          <div style={{ fontSize:'.68rem', color:'#6a6a64', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
            {detail || 'From station'}
          </div>
        </div>

        {/* Fare + ride links */}
        <div style={{ textAlign:'right', flexShrink:0 }}>
          <div style={{
            fontSize:'.76rem', fontWeight:800, color: isSelected ? meta.color : '#3a3a34',
            marginBottom: rides.length ? 4 : 0,
          }}>{actualFare}</div>
          {rides.length > 0 && (
            <div style={{ display:'flex', gap:4, justifyContent:'flex-end' }}>
              {rides.map(r => <RideBtn key={r} p={r} />)}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ── Step in journey summary ────────────────────────────── */
function Step({ n, label, detail, isLast }) {
  return (
    <div style={{ display:'flex', gap:10 }}>
      <div style={{ display:'flex', flexDirection:'column', alignItems:'center', flexShrink:0 }}>
        <div style={{
          width:22, height:22, borderRadius:'50%',
          background: G_BG, border:`1.5px solid ${G_BOR}`,
          display:'flex', alignItems:'center', justifyContent:'center',
          fontSize:'.64rem', fontWeight:700, color: G_DARK, flexShrink:0,
        }}>{n}</div>
        {!isLast && <div style={{ width:1.5, flex:1, minHeight:14, background:G_BOR, margin:'3px 0' }} />}
      </div>
      <div style={{ paddingBottom: isLast ? 0 : 12 }}>
        <div style={{ fontWeight:600, fontSize:'.8rem', color:'#1a1a18', marginBottom:1 }}>{label}</div>
        <div style={{ fontSize:'.68rem', color:'#6a6a64', lineHeight:1.45 }}>{detail}</div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════
   MAIN PAGE
════════════════════════════════════════════════════════ */
export default function LastMilePage({ appState, setAppState, onNavigate, speak }) {
  const { destStation, nearestStation, nearestBusStop, selectedTrain, destPlaceName, destPlaceCoords } = appState;

  const [selMode,    setSelMode]    = useState(null);
  const [busStop,    setBusStop]    = useState(null);
  const [suggestion, setSuggestion] = useState(null);
  const [allOptions, setAllOptions] = useState([]);
  const [destDist,   setDestDist]   = useState(null);
  const [bestExit,   setBestExit]   = useState(null);
  const [compass,    setCompass]    = useState('');
  const [navSteps,   setNavSteps]   = useState([]);

  useEffect(() => {
    if (!destStation) return;
    const bs = getLastMileBusStop(destStation);
    setBusStop(bs);

    if (destPlaceCoords?.found) {
      let dist = haversine(
        destStation.lat, destStation.lng,
        destPlaceCoords.lat, destPlaceCoords.lng
      );

      // ── Bug fix: if user selected the station itself as destination,
      //    coords match exactly → dist = 0. Use 350m minimum (station exit walk).
      if (dist < 50) dist = 350;

      setDestDist(dist);

      const sug  = getLastMileSuggestion(destStation.lat, destStation.lng, destPlaceCoords.lat, destPlaceCoords.lng, bs);
      const opts = getAllLastMileOptions(destStation.lat, destStation.lng, destPlaceCoords.lat, destPlaceCoords.lng, bs);
      const withBike = [...opts, { mode:'bike', label:'Bike Taxi', detail:'Fast 2-wheeler ride', fare: estimateFare('bike', dist), recommended:false }];
      setSuggestion(sug);
      setAllOptions(withBike);
      setSelMode(sug.mode);
      setAppState(s => ({ ...s, lastMileMode: sug.mode }));

      const exit = getBestExit(destStation, destPlaceCoords.lat, destPlaceCoords.lng);
      const bear = getBearing(destStation.lat, destStation.lng, destPlaceCoords.lat, destPlaceCoords.lng);
      setBestExit(exit);
      setCompass(bearingToCompass(bear));

      const steps = [];
      if (exit) {
        steps.push(`Exit towards the ${exit.side} side of the station`);
        exit.direction.split('→').forEach(p => { const t=p.trim(); if(t) steps.push(t); });
      }
      steps.push(`Walk ${distanceText(dist)} heading ${bearingToCompass(bear)}`);
      if (destPlaceName) steps.push(`Arrive at ${destPlaceName}`);
      setNavSteps(steps);

      let msg = `Arrived at ${destStation.name} station. `;
      if (exit) msg += `Take the ${exit.side} exit. `;
      if (sug.mode === 'walk')  msg += `Your destination is just a short walk away. `;
      else if (sug.mode === 'auto') msg += `Auto-rickshaw recommended from the exit. Estimated fare ${estimateFare('auto', dist)}. `;
      else if (sug.mode === 'bus')  msg += `Take bus number ${bs?.buses?.[0]} from ${bs?.name}. `;
      else msg += `Book a cab. Estimated fare ${estimateFare('cab', dist)}. `;
      speak(msg);
    } else {
      speak(`Arrived at ${destStation.name}. Choose your transport.`);
    }
  }, [destStation?.id]);

  const handleSelect = mode => {
    setSelMode(mode);
    setAppState(s => ({ ...s, lastMileMode: mode }));
  };

  const fallback = [
    { mode:'walk', label:'Walk',          detail:'If nearby',          recommended:false },
    { mode:'auto', label:'Auto-Rickshaw', detail:'Quick ride',          recommended:true  },
    { mode:'bus',  label:'Bus',           detail:'Most economical',     recommended:false },
    { mode:'cab',  label:'Cab / Taxi',    detail:'Comfortable & direct',recommended:false },
    { mode:'bike', label:'Bike Taxi',     detail:'Fast 2-wheeler',      recommended:false },
  ];
  const displayOptions = allOptions.length > 0 ? allOptions : fallback;

  if (!destStation) return (
    <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'100vh', background:'#fff', padding:'0 24px', textAlign:'center' }}>
      <p style={{ color:'#9a9a94', marginBottom:20 }}>Complete your journey plan first.</p>
      <button onClick={() => onNavigate('home')} style={{ padding:'12px 28px', borderRadius:50, border:'none', background:`linear-gradient(135deg,${G},#5a9a38)`, color:'#fff', fontFamily:'Inter, sans-serif', fontWeight:700, cursor:'pointer' }}>← Go Home</button>
    </div>
  );

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(145deg,#f4f7f0 0%,#edf4e8 35%,#f8fbf6 70%,#fff 100%)',
    }}>
      {/* Content */}
      <div style={{ paddingTop: 72 }}>

        {/* ── Header ── */}
        <div style={{
          background: 'rgba(255,255,255,.82)', backdropFilter: 'blur(20px)',
          borderBottom: '1px solid rgba(107,175,69,.15)',
          padding: '14px 44px 14px 52px',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          position: 'sticky', top: 72, zIndex: 100,
        }}>
          <div>
            <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:2 }}>
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                <circle cx="8" cy="5" r="2.5" stroke={G} strokeWidth="1.5" fill="none"/>
                <path d="M8 7.5 L8 13" stroke={G} strokeWidth="1.5" strokeLinecap="round"/>
                <path d="M5 15 Q8 13 11 15" stroke={G} strokeWidth="1.2" strokeLinecap="round" fill="none"/>
              </svg>
              <h1 style={{ fontFamily:'Playfair Display, serif', fontWeight:900, fontSize:'1.45rem', color:'#1a1a18' }}>
                Last Mile Guide
              </h1>
            </div>
            <p style={{ color:'#6a6a64', fontSize:'.78rem' }}>
              Arrived at <strong style={{ color:G }}>{destStation.name}</strong>
              {destDist && destDist > 50 && ` · ${distanceText(destDist)} to ${destPlaceName || 'destination'}`}
            </p>
          </div>
          <div style={{
            display:'flex', alignItems:'center', gap:7,
            background:'rgba(107,175,69,.2)', border:`1px solid ${G_BOR}`,
            borderRadius:20, padding:'6px 14px',
          }}>
            <div style={{ width:6, height:6, borderRadius:'50%', background:G, animation:'pulse 2.5s infinite' }} />
            <span style={{ fontSize:'.68rem', fontWeight:700, color:G, letterSpacing:.4 }}>Arrived</span>
          </div>
        </div>

        {/* ── Two-column layout ── */}
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', minHeight:'calc(100vh - 130px)', gap:0 }}>

          {/* LEFT — navigation instructions */}
          <div style={{ padding:'28px 32px 40px 52px', borderRight:'1px solid rgba(107,175,69,.12)' }}>

            {/* VISTA recommendation */}
            {suggestion && (
              <div style={{
                background:'rgba(107,175,69,.15)', backdropFilter:'blur(12px)',
                border:`1px solid ${G_BOR}`, borderRadius:12,
                padding:'9px 14px', marginBottom:16,
                display:'flex', alignItems:'center', gap:8,
              }}>
                <div style={{ width:6, height:6, borderRadius:'50%', background:G, animation:'pulse 2.5s infinite', flexShrink:0 }} />
                <span style={{ fontSize:'.72rem' }}>
                  <span style={{ fontWeight:700, color:G }}>VISTA recommends: </span>
                  <span style={{ color:'#4a7030' }}>
                    {TRANSPORT_META[suggestion.mode]?.label} · {estimateFare(suggestion.mode, destDist || 0)}
                  </span>
                </span>
              </div>
            )}

            {/* Exit + nav card */}
            <div style={{
              background:'#fff',
              border:'1px solid rgba(0,0,0,.07)',
              borderRadius:16, padding:'18px 20px', marginBottom:14,
              boxShadow:'0 2px 12px rgba(0,0,0,.05)',
            }}>
              <div style={{ fontSize:'.56rem', fontWeight:700, letterSpacing:'2px', textTransform:'uppercase', color:'#bbb', marginBottom:12 }}>
                Exit & Navigation
              </div>

              {bestExit && (
                <div style={{
                  display:'flex', alignItems:'center', gap:12, marginBottom:16,
                  background:`rgba(107,175,69,.15)`, border:`1px solid ${G_BOR}`,
                  borderRadius:12, padding:'12px 14px',
                }}>
                  <div style={{
                    width:46, height:46, borderRadius:'50%', flexShrink:0,
                    background:`linear-gradient(135deg,${G},#5a9a38)`,
                    display:'flex', alignItems:'center', justifyContent:'center',
                    fontSize:'1.4rem', fontWeight:900, color:'white',
                    boxShadow:`0 4px 16px rgba(107,175,69,.4)`,
                  }}>
                    {bestExit.side==='West'?'←':bestExit.side==='East'?'→':bestExit.side==='North'?'↑':'↓'}
                  </div>
                  <div>
                    <div style={{ fontWeight:800, fontSize:'.9rem', color:'#1a1a18', marginBottom:2 }}>
                      Exit towards the {bestExit.side} side
                    </div>
                    <div style={{ fontSize:'.7rem', color:'#6a6a64' }}>
                      {destStation.name} · Head {compass}
                    </div>
                  </div>
                </div>
              )}

              {navSteps.length > 0 && (
                <div>
                  {navSteps.map((step, i) => (
                    <div key={i} style={{ display:'flex', gap:10, marginBottom: i<navSteps.length-1 ? 8 : 0 }}>
                      <div style={{ display:'flex', flexDirection:'column', alignItems:'center', flexShrink:0 }}>
                        <div style={{
                          width:20, height:20, borderRadius:'50%',
                          background: i===0 ? G : 'rgba(107,175,69,.12)',
                          border:`1.5px solid ${i===0 ? G : G_BOR}`,
                          display:'flex', alignItems:'center', justifyContent:'center',
                          fontSize:'.6rem', fontWeight:700,
                          color: i===0 ? '#fff' : G_DARK,
                        }}>{String.fromCharCode(65+i)}</div>
                        {i < navSteps.length-1 && <div style={{ width:1.5, height:14, background:G_BOR, margin:'3px 0' }} />}
                      </div>
                      <div style={{ paddingTop:1 }}>
                        <div style={{ fontSize:'.77rem', color: i===0 ? '#1a1a18' : '#4a4a44', fontWeight: i===0 ? 700 : 400, lineHeight:1.45 }}>
                          {step}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {bestExit?.landmarks && (
                <div style={{
                  marginTop:14, display:'flex', alignItems:'flex-start', gap:6,
                  padding:'7px 10px', background:G_BG, borderRadius:8, border:`1px solid ${G_BOR}`,
                }}>
                  <svg width="12" height="12" viewBox="0 0 12 12" fill="none" style={{ flexShrink:0, marginTop:1 }}>
                    <circle cx="6" cy="4" r="2.5" stroke={G_DARK} strokeWidth="1.3" fill="none"/>
                    <path d="M6 6.5 L6 11" stroke={G_DARK} strokeWidth="1.3" strokeLinecap="round"/>
                  </svg>
                  <span style={{ fontSize:'.67rem', color:'#4a4a44', lineHeight:1.5 }}>
                    Nearby: {bestExit.landmarks}
                  </span>
                </div>
              )}
            </div>

            {/* Journey summary */}
            <div style={{
              background:'#fff',
              border:'1px solid rgba(0,0,0,.07)',
              borderRadius:14, padding:'16px 20px', marginBottom:14,
              boxShadow:'0 2px 12px rgba(0,0,0,.05)',
            }}>
              <div style={{ fontSize:'.56rem', fontWeight:700, letterSpacing:'2px', textTransform:'uppercase', color:'#bbb', marginBottom:12 }}>
                Journey Summary
              </div>
              <Step n="1" label="First Mile"
                detail={nearestBusStop ? `${nearestBusStop.name} → Bus ${nearestBusStop.buses[0]} → ${nearestStation?.name}` : `To ${nearestStation?.name}`}
              />
              <Step n="2" label="Board Train"
                detail={selectedTrain ? `${selectedTrain.trainName||selectedTrain.name} · ${selectedTrain.departureTime||selectedTrain.nextTime||''} · Plat ${selectedTrain.platform||selectedTrain.platform_south||1}` : 'See Train Schedule'}
              />
              <Step n="3" label={`Exit at ${destStation.name}`}
                detail={bestExit ? `Take the ${bestExit.side} exit · ${bestExit.direction.split('→')[0].trim()}` : destStation.name}
              />
              <Step n="4" label={`Reach ${destPlaceName||'Destination'}`}
                detail={destDist && destDist > 50 ? `${distanceText(destDist)} · ${TRANSPORT_META[selMode||'auto']?.label}` : 'Select transport option'}
                isLast
              />
            </div>

            {/* Action buttons */}
            <div style={{ display:'flex', gap:10 }}>
              <button
                onClick={() => speak([
                  `Arrived at ${destStation.name} station.`,
                  bestExit ? `Take the ${bestExit.side} exit.` : '',
                  selMode === 'walk' ? 'Your destination is a short walk from the exit.' :
                  selMode === 'auto' ? `Take an auto-rickshaw. Estimated fare ${estimateFare('auto', destDist||0)}.` :
                  selMode === 'cab'  ? `Book a cab. Estimated fare ${estimateFare('cab', destDist||0)}.` : '',
                ].filter(Boolean).join(' '))}
                style={{
                  flex:1, padding:'11px 0', borderRadius:12,
                  background:'rgba(107,175,69,.1)', backdropFilter:'blur(8px)',
                  border:`1px solid ${G_BOR}`,
                  cursor:'pointer', fontFamily:'Inter, sans-serif',
                  fontWeight:600, fontSize:'.82rem', color: G_DARK, transition:'all .2s',
                }}
                onMouseEnter={e=>e.currentTarget.style.background='rgba(107,175,69,.18)'}
                onMouseLeave={e=>e.currentTarget.style.background='rgba(107,175,69,.1)'}
              >Hear Summary</button>
              <button
                onClick={() => {
                  setAppState(s => ({ ...s, destStation:null, selectedTrain:null, lastMileMode:null, destPlaceName:null, destPlaceCoords:null }));
                  onNavigate('home');
                  speak('Starting a new journey.');
                }}
                style={{
                  flex:2, padding:'11px 0', borderRadius:12,
                  background:`linear-gradient(135deg,${G},#5a9a38)`,
                  border:'none', cursor:'pointer',
                  fontFamily:'Inter, sans-serif', fontWeight:700,
                  fontSize:'.88rem', color:'#fff',
                  boxShadow:'0 4px 18px rgba(107,175,69,.35)',
                  transition:'all .22s',
                }}
                onMouseEnter={e=>{ e.currentTarget.style.transform='translateY(-1px)'; e.currentTarget.style.boxShadow='0 6px 22px rgba(107,175,69,.5)'; }}
                onMouseLeave={e=>{ e.currentTarget.style.transform='none'; e.currentTarget.style.boxShadow='0 4px 18px rgba(107,175,69,.35)'; }}
              >Plan New Journey</button>
            </div>
          </div>

          {/* RIGHT — compact transport glass cards */}
          <div style={{ padding:'28px 48px 40px 24px', background:'#fafaf8' }}>
            <div style={{ fontSize:'.56rem', fontWeight:700, letterSpacing:'2px', textTransform:'uppercase', color:'#bbb', marginBottom:12 }}>
              Transport Options
            </div>

            {displayOptions.map((opt, i) => (
              <GlassCard
                key={opt.mode}
                mode={opt.mode}
                detail={opt.detail}
                fare={opt.fare}
                recommended={opt.recommended}
                isSelected={selMode === opt.mode}
                onSelect={handleSelect}
                distMeters={destDist || 0}
              />
            ))}

            {/* Bus stop info */}
            {busStop && (
              <div style={{
                background:'#fff',
                border:'1px solid rgba(0,0,0,.07)',
                borderRadius:12, padding:'14px 16px', marginTop:6,
                boxShadow:'0 2px 10px rgba(0,0,0,.05)',
              }}>
                <div style={{ fontSize:'.55rem', fontWeight:700, letterSpacing:'2px', textTransform:'uppercase', color:'#bbb', marginBottom:6 }}>
                  Nearest Bus Stop
                </div>
                <div style={{ fontWeight:700, fontSize:'.84rem', color:'#1a1a18', marginBottom:6 }}>{busStop.name}</div>
                <div style={{ display:'flex', gap:5, flexWrap:'wrap' }}>
                  {busStop.buses.map(b => (
                    <span key={b} style={{
                      padding:'2px 9px', borderRadius:20, fontSize:'.66rem', fontWeight:600,
                      background: G_BG, color: G_DARK,
                      border:`1px solid ${G_BOR}`,
                    }}>{b}</span>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
